imple|13=User:Immanuelle/2216|comment=likely broken Sexagenary year|lt=2216 AD|qq=|ja_comment=jawiki redirects to 23ไธ็ด}} * {{ill|2276 AD|ja|2276ๅนด|qq=draft|qq=draft|qq=|12=simple|13=User:Immanuelle/2276|comment=likely broken Sexagenary year|lt=2276 AD|qq=|ja_comment=jawiki redirects to 23ไธ็ด}} * {{ill|2336 AD|ja|2336ๅนด|qq=draft|qq=draft|qq=|12=simple|13=User:Immanuelle/2336|comment=likely broken Sexagenary year|lt=2336 AD|qq=|ja_comment=jawiki link invalid}} * {{ill|2396 AD|ja|2396ๅนด|qq=draft|qq=draft|qq=|12=simple|13=User:Immanuelle/2396|comment=likely broken Sexagenary year|lt=2396 AD|qq=|ja_comment=jawiki link invalid}} * {{ill|2456 AD|ja|2456ๅนด|qq=draft|qq=draft|qq=|12=simple|13=User:Immanuelle/2456|comment=likely broken Sexagenary year|lt=2456 AD|qq=|ja_comment=jawiki link invalid}} * {{ill|2516 AD|ja|2516ๅนด|qq=draft|qq=draft|qq=|12=simple|13=User:Immanuelle/2516|comment=likely broken Sexagenary year|lt=2516 AD|qq=|ja_comment=jawiki link invalid}} * {{ill|2576 AD|ja|2576ๅนด|qq=draft|qq=draft|qq=|12=simple|13=User:Immanuelle/2576|comment=likely broken Sexagenary year|lt=2576 AD|qq=|ja_comment=jawiki link invalid}} * {{ill|2636 AD|ja|2636ๅนด|qq=draft|qq=draft|qq=|12=simple|13=User:Immanuelle/2636|comment=likely broken Sexagenary year|lt=2636 AD|qq=|ja_comment=jawiki link invalid}} * {{ill|2696 AD|ja|2696ๅนด|qq=draft|qq=draft|qq=|12=simple|13=User:Immanuelle/2696|comment=likely broken Sexagenary year|lt=2696 AD|qq=|ja_comment=jawiki link invalid}} * {{ill|2756 AD|ja|2756ๅนด|qq=draft|qq=draft|qq=|12=simple|13=User:Immanuelle/2756|comment=likely broken Sexagenary year|lt=2756 AD|qq=|ja_comment=jawiki link invalid}} * {{ill|2816 AD|ja|2816ๅนด|qq=draft|qq=draft|qq=|12=simple|13=User:Immanuelle/2816|comment=likely broken Sexagenary year|lt=2816 AD|qq=|ja_comment=jawiki link invalid}} * {{ill|2876 AD|ja|2876ๅนด|qq=draft|qq=draft|qq=|12=simple|13=User:Immanuelle/2876|comment=likely broken Sexagenary year|lt=2876 AD|qq=|ja_comment=jawiki link invalid}} * {{ill